var d = $input.first().json;

// Default models per task
var defaultModels = {
  text_generation:    'mistralai/Mistral-7B-Instruct-v0.2',
  summarization:      'facebook/bart-large-cnn',
  sentiment_analysis: 'distilbert-base-uncased-finetuned-sst-2-english',
  translation:        'Helsinki-NLP/opus-mt-en-fr',
  image_generation:   'stabilityai/stable-diffusion-xl-base-1.0'
};

var task  = d.task || 'summarization';
var model = d.customModel || defaultModels[task] || defaultModels['summarization'];
var input = d.inputText || '';

if (!input) {
  throw new Error('Missing input field. Please provide text in the input field.');
}

// Build payload per task type
var payload = {};
if (task === 'text_generation') {
  payload = {
    inputs: input,
    parameters: { max_new_tokens: 512, temperature: 0.7, return_full_text: false }
  };
} else if (task === 'summarization') {
  payload = {
    inputs: input,
    parameters: { max_length: 200, min_length: 50, do_sample: false }
  };
} else if (task === 'sentiment_analysis') {
  payload = { inputs: input };
} else if (task === 'translation') {
  payload = { inputs: input };
} else if (task === 'image_generation') {
  payload = {
    inputs: input,
    parameters: { num_inference_steps: 30, guidance_scale: 7.5 }
  };
} else {
  payload = { inputs: input };
}

// Merge any extra user params
try {
  var extra = JSON.parse(d.extraParams || '{}');
  if (extra && typeof extra === 'object') {
    payload.parameters = Object.assign(payload.parameters || {}, extra);
  }
} catch(e) {}

return [{ json: {
  jobId:       d.jobId,
  task:        task,
  model:       model,
  payload:     payload,
  payloadJson: JSON.stringify(payload),
  HF_API_KEY:  d.HF_API_KEY,
  startedAt:   new Date().toISOString()
}}];

var raw  = $('Call Hugging Face API').first().json;
var meta = $('Build Model Payload').first().json;

var task   = meta.task || 'unknown';
var result = null;
var label  = '';
var score  = null;

try {
  // HF returns different shapes per task
  if (Array.isArray(raw)) {
    var first = raw[0];

    if (task === 'text_generation') {
      result = (first.generated_text || '').trim();

    } else if (task === 'summarization') {
      result = (first.summary_text || '').trim();

    } else if (task === 'sentiment_analysis') {
      // Can be nested array
      var item = Array.isArray(first) ? first[0] : first;
      label  = item.label || '';
      score  = item.score ? parseFloat(item.score.toFixed(4)) : null;
      result = label + ' (' + (score !== null ? (score * 100).toFixed(1) + '%' : '') + ' confidence)';

    } else if (task === 'translation') {
      result = (first.translation_text || '').trim();

    } else if (task === 'image_generation') {
      // Binary/blob — HF returns base64 in some endpoints
      result = '[Image generated — use binary output mode for image bytes]';

    } else {
      result = JSON.stringify(first);
    }

  } else if (raw && typeof raw === 'object') {
    // Some models return object directly
    result = raw.generated_text || raw.summary_text || raw.translation_text || JSON.stringify(raw);
  } else {
    result = String(raw);
  }
} catch(e) {
  result = 'Parse error: ' + e.message;
}

return [{ json: {
  success:       true,
  jobId:         meta.jobId,
  task:          task,
  model:         meta.model,
  result:        result,
  label:         label || null,
  score:         score,
  resultLength:  (result || '').length,
  completedAt:   new Date().toISOString()
}}];
